def fmt_num(x, suffix=""):
    if abs(x) >= 1_000_000:
        return f"{x/1_000_000:,.2f}M{suffix}"
    if abs(x) >= 1_000:
        return f"{x/1_000:,.1f}K{suffix}"
    return f"{x:,.0f}{suffix}"


def kpi_card(col, label, value, glow_color, sub=None, sub_color=None, icon=""):
    with col:
        st.markdown(f"""
        <div class="kpi-card">
            <div class="kpi-glow" style="background:{glow_color};"></div>
            <div class="kpi-label">{icon} {label}</div>
            <div class="kpi-value">{value}</div>
            {f'<div class="kpi-sub" style="color:{sub_color};">{sub}</div>' if sub else ''}
        </div>
        """, unsafe_allow_html=True)


def section_title(title_ar, title_en, color):
    st.markdown(f"""
    <div class="sec-title"><span class="bar" style="background:{color};"></span>{title_ar}</div>
    <div class="sec-sub">{title_en}</div>
    """, unsafe_allow_html=True)


def style_fig(fig, height=380):
    fig.update_layout(
        template=CHART_TEMPLATE,
        paper_bgcolor=PANEL,
        plot_bgcolor=PANEL,
        font=dict(color=TEXT, family="Space Grotesk", size=14),
        height=height,
        margin=dict(l=10, r=10, t=30, b=10),
        legend=dict(bgcolor="rgba(0,0,0,0)", orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1,
                    font=dict(size=13)),
        hoverlabel=dict(bgcolor=PANEL_2, font_size=13, font_family="Space Grotesk", font_color=TEXT),
    )
    fig.update_xaxes(
        showgrid=True, gridcolor=GRID_COLOR, gridwidth=1, zeroline=False,
        showline=True, linecolor=BORDER, linewidth=1,
        tickfont=dict(size=13, color=TEXT),
    )
    fig.update_yaxes(
        showgrid=True, gridcolor=GRID_COLOR, gridwidth=1, zeroline=False,
        showline=True, linecolor=BORDER, linewidth=1,
        tickfont=dict(size=13, color=TEXT),
    )
    return fig


def clarify_ton_axis(fig, axis_title="الإنتاج (طن)", hover_suffix=" طن"):
    """Plotly auto-abbreviates large numbers on the axis (e.g. '150k'),
    which reads as an ambiguous unit since our numbers are already in Tons
    (not thousands of Tons). This disables that abbreviation, shows full
    comma-separated figures, and labels the axis clearly."""
    fig.update_yaxes(title_text=axis_title, title_font=dict(size=13, color=SUBTEXT),
                      tickformat=",.0f", separatethousands=True)
    fig.update_traces(hovertemplate="%{y:,.0f}" + hover_suffix + "<extra></extra>")
    return fig


def pick_scale(*arrays):
    """Pick ONE shared K / M scale for one or more numeric arrays/series,
    using the same thresholds as fmt_num (>=1M -> million, >=1K -> thousand,
    otherwise plain numbers). Charts that show more than one series (e.g.
    Cost vs Revenue) should pass all of them together so both bars end up
    on the same scale. Returns (divisor, short_suffix) where short_suffix
    is 'K' / 'M' / '' — meant to be shown directly next to each axis tick
    (via ticksuffix), not written out as separate title text."""
    vals = []
    for a in arrays:
        if a is None:
            continue
        s = pd.Series(a).dropna()
        if len(s):
            vals.append(s.abs().max())
    max_abs = max(vals) if vals else 0
    if max_abs >= 1_000_000:
        return 1_000_000, "M"
    if max_abs >= 1_000:
        return 1_000, "K"
    return 1, ""


@st.cache_data(show_spinner=False)
def load_data():
    raw = gzip.decompress(base64.b64decode(_DATA_B64))
    df = pd.read_excel(io.BytesIO(raw))
    df["Date"] = pd.to_datetime(df["Date"])
    return df


