# ---- Packing Type (نوع التعبئة) detection ----
# The dashboard expects the raw data to contain a column describing whether
# each record is "Packed" (معبأ) or "Bulk" (سائب). We try a handful of
# common column names so this keeps working even if the sheet uses a
# slightly different header. If none is found, the filter still appears
# but has no effect on the data (a small notice is shown in the sidebar).
PACKING_COL_CANDIDATES = [
    "Packing_Type", "Fill_Type", "Pack_Type", "Filling_Type",
    "Type_Packing", "PackingType", "نوع_التعبئة", "التعبئة", "Packing Type",
]
packing_col = next((c for c in PACKING_COL_CANDIDATES if c in df.columns), None)


def _norm_packing(v):
    s = str(v).strip().lower()
    if s in ("packed", "pack", "معبأ", "معبأة", "معبأه"):
        return "معبأ (Packed)"
    if s in ("bulk", "سائب", "سايب"):
        return "سائب (Bulk)"
    return str(v).strip()


if packing_col:
    df["Packing_Type_AR"] = df[packing_col].apply(_norm_packing)
    packing_present = sorted(df["Packing_Type_AR"].dropna().unique().tolist())
else:
    df["Packing_Type_AR"] = None
    packing_present = ["معبأ (Packed)", "سائب (Bulk)"]

