total_revenue = fdf["Total_Revenue"].sum()
total_cost = fdf["Total_Cost"].sum()
total_profit = fdf["Net_Profit"].sum()
profit_margin = (total_profit / total_revenue * 100) if total_revenue else 0

c1, c2, c3, c4, c5 = st.columns(5)
kpi_card(c1, "إجمالي الإنتاج (Ton)", fmt_num(total_production, " طن"), COPPER, icon="📦")
kpi_card(c2, "إجمالي الإيرادات", fmt_num(total_revenue, " ج.م"), CYAN, icon="💰")
kpi_card(c3, "إجمالي التكلفة", fmt_num(total_cost, " ج.م"), ROSE, icon="🧾")
kpi_card(c4, "صافي الربح", fmt_num(total_profit, " ج.م"), VIOLET,
         sub=f"▲ {profit_margin:.1f}% هامش ربح", sub_color=EMERALD, icon="📈")
kpi_card(c5, "متوسط الإنتاج اليومي", fmt_num(fdf.groupby('Date')['Quantity_Ton'].sum().mean(), " طن"), EMERALD, icon="⚙️")

st.markdown("<br>", unsafe_allow_html=True)

# ============================================================
# AGGREGATIONS
# ============================================================
monthly = (
    fdf.groupby("Month_Name_EN", observed=True)
    .agg(Production=("Quantity_Ton", "sum"),
         Revenue=("Total_Revenue", "sum"),
         Cost=("Total_Cost", "sum"),
         Profit=("Net_Profit", "sum"))
    .reset_index()
    .sort_values("Month_Name_EN")
)

type_contribution = (
    fdf.groupby("Product_Type")["Quantity_Ton"].sum().reset_index().sort_values("Quantity_Ton", ascending=False)
)

top5_types = type_contribution.head(5)["Product_Type"].tolist()
top5_monthly = (
    fdf[fdf["Product_Type"].isin(top5_types)]
    .groupby(["Month_Name_EN", "Product_Type"], observed=True)["Quantity_Ton"]
    .sum()
    .reset_index()
    .sort_values("Month_Name_EN")
)

packed_bulk_daily = fdf.groupby("Date").agg(
    Packed=("Day_Packed_Ton", "first"),
    Bulk=("Day_Bulk_Ton", "first"),
    Month_Name_EN=("Month_Name_EN", "first"),
).reset_index()
packed_bulk_monthly = (
    packed_bulk_daily.groupby("Month_Name_EN", observed=True)
    .agg(Packed=("Packed", "sum"), Bulk=("Bulk", "sum"))
    .reset_index()
    .sort_values("Month_Name_EN")
)

# ============================================================
# ROW 1 — Production & Revenue trends
# ============================================================
col1, col2 = st.columns(2)

with col1:
    section_title("اتجاه الإنتاج الشهري", "Monthly Production Trend", COPPER)
    p_div, p_scale = pick_scale(monthly["Production"])
